import { G, T, A, O, P } from './domains.js';

export const part4 = [
  {id:379,domain:G,question:"What is the purpose of certificate transparency (CT) logs?",options:["Public log of issued certificates","Encrypting certificate metadata in transit","Distributing real-time revocation status","Archiving expired certificates for history"],answer:0,explanation:"CT logs allow domain owners and browsers to detect unauthorized certificates issued for their domains (catching rogue CAs and certificate abuse).",optionExplanations:["CT logs make certificate issuance public and auditable, exposing unauthorized certs.","CT logs make issuance public, not encrypted; they don't encrypt certificate data.","CRL/OCSP distribute revocation status; CT logs document issuance instead.","CT logs record new certificates as issued, not archive expired ones."]},
  {id:380,domain:T,question:"What is a supply chain attack?",options:["Ransomware against shipping systems","Same malware against many unrelated targets","Physically stealing warehouse goods","Compromising a less-secure vendor to reach the real target"],answer:3,explanation:"Supply chain attacks like SolarWinds compromise trusted software/hardware that targets install, achieving broad access via a trusted channel.",optionExplanations:["Ransomware against logistics systems is a direct attack, not via a vendor.","Broad campaigns hitting unrelated targets don't exploit vendor trust specifically.","Physical theft is a facility security incident, not a digital supply chain compromise.","Supply chain attacks compromise a trusted vendor to reach a higher-value target."]},
  {id:381,domain:A,question:"What is containerization from a security perspective?",options:["Apps sharing a kernel, isolated via namespaces","Encrypting data at rest and in transit","Each app in its own full virtual machine","Physically isolating hardware servers"],answer:0,explanation:"Container security relies on kernel namespace isolation, but containers share the host kernel — a kernel exploit can escape all containers on that host.",optionExplanations:["Containers use namespaces and cgroups for isolation but share the host kernel.","Encryption is a separate control, not what defines containerization.","VMs provide full separate OS isolation; containers share the host kernel instead.","Physical server isolation is hardware-level, unlike OS-level containerization."]},
  {id:382,domain:P,question:"What is data sovereignty?",options:["Government ownership of citizen data","Encrypting data with government-approved algorithms","Owning IP rights to proprietary data","Data is governed by the laws of its storage location"],answer:3,explanation:"Data sovereignty concerns arise when organizations store data in foreign countries where local laws may compel disclosure without the data owner's consent.",optionExplanations:["Sovereignty is about legal jurisdiction, not government data ownership.","Approved encryption algorithms are a separate compliance requirement in some regions.","IP ownership is a distinct legal concept from data sovereignty.","Data sovereignty means data is subject to the laws of its storage location."]},
  {id:383,domain:O,question:"What is the purpose of a security operations center (SOC)?",options:["Centralized threat monitoring team","Performing periodic annual security audits","Managing IT uptime and capacity","Defining software security requirements"],answer:0,explanation:"SOCs provide 24/7 monitoring, alert triage, threat hunting, and incident response coordination to maintain organizational security posture.",optionExplanations:["A SOC centralizes tools and analysts for continuous detection and response.","Annual audits are periodic; a SOC provides ongoing, round-the-clock operations.","IT performance is managed by a NOC, not a SOC.","Security requirements are set during development, not by SOC operations."]},
  {id:384,domain:T,question:"What is DNS poisoning (DNS cache poisoning)?",options:["Deleting legitimate DNS records","Flooding a DNS server with requests","Encrypting DNS query traffic","Inserting fraudulent DNS records into a resolver's cache"],answer:3,explanation:"DNS poisoning redirects traffic by corrupting cached DNS responses, sending users to attacker-controlled IPs while they believe they're visiting legitimate sites.",optionExplanations:["Deleting records causes unavailability; poisoning redirects traffic instead.","Flooding a DNS server is a DoS attack, not cache corruption.","DoH/DoT encrypt queries; poisoning attacks the integrity of cached records.","Poisoning inserts malicious entries redirecting users to attacker-controlled servers."]},
  {id:385,domain:G,question:"What is the principle of non-repudiation?",options:["Ensuring all parties remain anonymous","Deleting transaction records from logs","Cannot deny performing an action","Preventing unauthorized record access"],answer:2,explanation:"Non-repudiation (achieved through digital signatures and audit logs) ensures entities cannot deny actions — essential for legal accountability and forensics.",optionExplanations:["Anonymity contradicts non-repudiation, which requires traceable identity.","Deleting records would undermine non-repudiation, not support it.","Non-repudiation ensures an action or message cannot be credibly denied.","Preventing unauthorized access describes confidentiality, not non-repudiation."]},
  {id:386,domain:A,question:"What is a reverse proxy and how does it improve security?",options:["VPN server for remote employees","Caching proxy for performance only","Firewall blocking outbound traffic","Server hiding backend identity"],answer:3,explanation:"Reverse proxies hide server architecture, terminate SSL, apply WAF rules, provide DDoS protection, and load balance — all in a security-controlled layer.",optionExplanations:["VPNs provide remote connectivity; reverse proxies control inbound web access.","Forward proxies mainly cache for performance; reverse proxies focus on security and routing.","Outbound blocking is a forward proxy/egress firewall job, not a reverse proxy's.","A reverse proxy fronts web servers, hiding backend identity and enforcing controls."]},
  {id:387,domain:O,question:"What is digital forensics chain of custody?",options:["Unbroken record of evidence handling","Notifying law enforcement of a cybercrime","Decrypting data on seized devices","Recovering deleted or hidden files"],answer:0,explanation:"Chain of custody ensures evidence is admissible in court by proving it was not tampered with and was handled by accountable, documented individuals.",optionExplanations:["Chain of custody tracks every transfer of evidence to prove its integrity.","Law enforcement notification is a separate incident response step.","Decryption is a technical forensic step, not the custody documentation itself.","File recovery is a forensic technique, not the documentation framework."]},
  {id:388,domain:T,question:"What is a man-in-the-browser (MiTB) attack?",options:["Injecting ads into web pages","Malware altering browser transactions","Physical attack on browser hosting servers","Stealing saved browser history and passwords"],answer:1,explanation:"MiTB malware sits inside the browser, modifying transactions (like changing bank transfer amounts) after the user initiates them but before encryption.",optionExplanations:["Ad injection is adware behavior, not transaction manipulation.","MiTB malware intercepts and alters transactions inside the browser before encryption.","Physical server attacks are unrelated to in-browser malware.","Stealing saved credentials is done by keyloggers, not live transaction tampering."]},
  {id:389,domain:P,question:"What is the purpose of an acceptable use policy (AUP)?",options:["Coding and development standards","Permitted and prohibited tech use","Network architecture layout","Physical security requirements for offices"],answer:1,explanation:"AUPs set clear expectations for technology use, provide legal basis for disciplinary action, and help establish reasonable personal use boundaries.",optionExplanations:["Coding standards are secure development guidelines, not an AUP.","An AUP defines permitted and prohibited uses of organizational technology.","Network architecture is documented in technical diagrams, not an AUP.","Physical security requirements are a separate policy from acceptable use."]},
  {id:390,domain:G,question:"What is the difference between hashing and encryption?",options:["Encryption is always faster than hashing","Hashing and encryption are the same process","Hashing is one-way; encryption is reversible","Hashing always needs a key; encryption never does"],answer:2,explanation:"Hashing cannot be reversed to retrieve the original data — it's for integrity verification, not confidentiality. Encryption can be reversed with the key.",optionExplanations:["Speed varies by algorithm; there's no universal advantage either way.","They serve different purposes and aren't interchangeable processes.","Hashing can't be reversed; encryption can be decrypted with the correct key.","This is backwards — encryption typically needs a key, standard hashing doesn't."]},
  {id:391,domain:T,question:"What is a fileless malware attack?",options:["Encrypting files while keeping originals","Exploiting PDF reader vulnerabilities","Runs in memory, no disk files","Hiding payloads in image pixel data"],answer:2,explanation:"Fileless malware (using PowerShell, WMI, registry) is difficult to detect with traditional AV since it never writes files to disk that can be scanned.",optionExplanations:["File-encrypting malware that withholds deletion describes ransomware, not fileless malware.","PDF exploits are a delivery method, not the fileless technique itself.","Fileless malware stays memory-resident, using tools like PowerShell without disk artifacts.","Hiding data in images is steganography, a different technique."]},
  {id:392,domain:A,question:"What is a DMZ (demilitarized zone) in network security?",options:["Zone for managing wireless access points","A buffer zone hosting public-facing internet services","Zone reserved for monitoring tools","Zone where no traffic is ever permitted"],answer:1,explanation:"DMZs host web servers, mail servers, and DNS servers that need internet exposure while the firewall prevents direct internet access to internal systems.",optionExplanations:["A wireless-only zone isn't the DMZ concept.","A DMZ hosts public-facing services, isolated from the internal network by firewalls.","Monitoring tools typically live in a separate management network, not the DMZ.","A DMZ carries active, carefully controlled traffic, not zero activity."]},
  {id:393,domain:O,question:"What is the purpose of a honeypot in network security?",options:["Collecting honey bees for sustainability","Decoy system detecting attackers","Database for storing digital certificates","Blocking malicious traffic at the perimeter"],answer:1,explanation:"Honeypots distract attackers, provide intelligence on TTPs, trigger alerts when accessed (since no legitimate user should access them), and slow down attacks.",optionExplanations:["This is unrelated to beekeeping; honeypot is a security deception term.","A honeypot mimics a real system to lure attackers and gather intelligence.","Certificate storage is handled by CAs and trust stores, not a honeypot.","Perimeter blocking is a firewall/IPS job; honeypots deliberately allow interaction."]},
  {id:394,domain:T,question:"What is DNS hijacking?",options:["Redirecting to rogue resolvers","Creating wildcard DNS records","Registering expired domain names","Flooding DNS servers with queries"],answer:0,explanation:"DNS hijacking redirects victims through malicious resolvers that can modify all DNS responses, enabling MitM attacks, phishing, and traffic interception.",optionExplanations:["Hijacking changes DNS resolver settings so queries route through attacker infrastructure.","Wildcard records are a legitimate DNS feature, not an attack.","Registering expired domains is domain squatting, not modifying existing settings.","Flooding a DNS server is a DoS attack, not redirecting resolution."]},
  {id:395,domain:G,question:"What is elliptic curve cryptography (ECC)?",options:["A family of cryptographic hash functions","Asymmetric method with smaller keys","Symmetric key exchange protocol","Symmetric block cipher for fixed-size chunks"],answer:1,explanation:"ECC achieves equivalent security to RSA-2048 with only 256-bit keys, making it ideal for resource-constrained devices and mobile applications.",optionExplanations:["Hash functions like SHA produce digests; ECC is an asymmetric key algorithm.","ECC uses elliptic curve math to match RSA security with much smaller keys.","ECDH is a variant, but ECC overall is an asymmetric system, not just key exchange.","Block ciphers like AES are symmetric; ECC is fundamentally asymmetric."]},
  {id:396,domain:P,question:"What is consent management in data privacy?",options:["Negotiating contracts with data processors","Approving security tool configuration changes","Managing admin access privileges","Obtaining, recording, and honoring individuals' data consent"],answer:3,explanation:"Consent management is critical for GDPR compliance — organizations must obtain specific, informed consent and be able to prove it and honor withdrawals.",optionExplanations:["Processor contracts are DPAs, a separate concept from individual consent.","Configuration approval is a change management task, unrelated to consent.","Admin access is managed by IAM, not consent management.","Consent management records and enforces individuals' permissions over their data."]},
  {id:397,domain:A,question:"What is the zero trust security model?",options:["Blocking every external connection","Verifying every user and device","Prohibiting all access to sensitive data","Trusting all traffic from inside the network"],answer:1,explanation:"Zero trust ('never trust, always verify') eliminates the concept of a trusted internal network — all access requires authentication, authorization, and continuous validation.",optionExplanations:["Zero trust verifies connections rather than blocking all external access outright.","Zero trust requires verifying identity and context for every access request.","Zero trust grants verified least-privilege access, not a total ban.","Implicit trust of internal traffic is the traditional model zero trust rejects."]},
  {id:398,domain:O,question:"What is a security baseline?",options:["Minimum secure configuration standard","Starting point for a penetration test","Tool for measuring network traffic patterns","The single weakest point in an organization"],answer:0,explanation:"Security baselines define minimum required configurations (patching, disabled services, password policies) ensuring consistent security posture across similar systems.",optionExplanations:["A baseline defines the minimum security configuration systems must meet.","Pen tests start from an attacker's perspective, not a defensive baseline.","Traffic analysis tools are monitoring utilities, not a configuration standard.","A weak point is one vulnerability finding, not a defined configuration standard."]},
  {id:399,domain:T,question:"What is tailgating in physical security?",options:["Slipping in behind an authorized person","Intercepting wireless communications nearby","Monitoring someone's online activity covertly","Attaching a hardware implant to a server"],answer:0,explanation:"Tailgating bypasses physical access controls (key cards, PINs) by piggybacking on an authorized person's entry — social courtesy enables the attack.",optionExplanations:["Tailgating enters a secure area right behind an authorized person, bypassing credentials.","Intercepting communications is eavesdropping or MitM, not physical entry.","Monitoring online activity is cyberstalking/OSINT, not physical building entry.","Attaching hardware implants is a distinct hardware attack, not tailgating."]},
  {id:400,domain:G,question:"What is the Diffie-Hellman key exchange?",options:["Two parties agree on a shared secret key","Hash function generating message digests","Protocol for publishing certificate revocation","Symmetric algorithm encrypting with one shared key"],answer:0,explanation:"DH enables two parties to derive the same shared secret using public values and private values, without ever transmitting the secret itself.",optionExplanations:["Diffie-Hellman lets two parties derive the same shared secret without transmitting it.","Hash functions like SHA produce digests; DH establishes a shared secret instead.","CRL/OCSP handle revocation; DH is a key exchange mechanism, unrelated.","DH is a key exchange method, not an encryption algorithm itself."]},
  {id:401,domain:T,question:"What is vishing?",options:["Voice phishing over the phone","Smishing","Deepfake video phishing","VoIP system exploitation"],answer:0,explanation:"Vishing attacks impersonate banks, IRS, tech support, or government agencies via phone, creating urgency to extract credentials, SSNs, or payments.",optionExplanations:["Vishing uses phone calls, often spoofed, to trick victims into revealing information.","Smishing is the term for SMS-based phishing, not vishing.","Deepfake video phishing is a distinct emerging tactic, not vishing.","Exploiting VoIP vulnerabilities is a technical attack, not the social engineering used in vishing."]},
  {id:402,domain:A,question:"What is infrastructure as code (IaC) from a security perspective?",options:["Autonomous deployment with no teams","Infrastructure defined as code","Writing exploit code against infrastructure","Reducing cloud infrastructure costs"],answer:1,explanation:"IaC enables security review of infrastructure configurations, consistent secure deployments, and detection of configuration drift through code review and scanning.",optionExplanations:["IaC tools assist teams; they do not eliminate the need for them.","IaC treats infrastructure configuration as code, enabling review and consistent deployment.","Writing exploit code is offensive testing, not IaC.","Cost optimization is a separate discipline from IaC."]},
  {id:403,domain:O,question:"What is purple teaming?",options:["APT simulation exercise","Web app penetration test team","Red/blue team collaboration","Uniforms colored red and blue"],answer:2,explanation:"Purple teaming breaks down the adversarial separation of red vs. blue, creating collaborative learning sessions that improve both offensive techniques and defensive detections.",optionExplanations:["APT simulation can occur in exercises but isn't the defining trait of purple teaming.","Web app pentesting is a specific red team activity, not purple teaming.","Purple teaming has red and blue teams share techniques in real time to improve detection.","The purple metaphor is about blending roles and knowledge, not literal uniforms."]},
  {id:404,domain:T,question:"What is a logic bomb?",options:["Self-replicating network worm","Code that executes on a specific trigger","Unintentional DoS from buggy logic","Buffer overflow exploit"],answer:1,explanation:"Logic bombs are often planted by insiders (disgruntled employees) and can destroy data, disrupt operations, or exfiltrate information when conditions trigger.",optionExplanations:["Self-replicating spread describes a worm, not a logic bomb.","A logic bomb stays dormant until a date, event, or condition activates it.","An accidental DoS from a bug isn't a deliberately planted logic bomb.","Buffer overflow is a memory exploitation technique, not a dormant trigger."]},
  {id:405,domain:G,question:"What is stream ciphers vs. block ciphers?",options:["Block ciphers only for wireless","Same algorithm, two marketing names","Stream ciphers always slower","Stream encrypts bit-by-bit; block encrypts fixed chunks"],answer:3,explanation:"Stream ciphers (RC4) are fast and good for real-time communications; block ciphers (AES) are used for bulk data encryption with modes like CBC or GCM.",optionExplanations:["Both cipher types are used across wired and wireless networks.","Stream and block ciphers are fundamentally different designs, not renamed duplicates.","Speed depends on implementation; neither type is inherently always faster.","Stream ciphers XOR a keystream with plaintext; block ciphers encrypt fixed-size blocks like AES's 128-bit blocks."]},
  {id:406,domain:P,question:"What is the purpose of a data processing agreement (DPA)?",options:["IT maintenance support contract","Contract for personal data processing","SLA for support response times","Software licensing contract"],answer:1,explanation:"DPAs (required by GDPR Article 28) ensure data processors implement appropriate security and only process data per the controller's instructions.",optionExplanations:["General IT maintenance agreements don't address personal data handling.","A DPA defines security requirements and obligations for processing personal data.","SLAs cover availability and response times, not data protection obligations.","Software license contracts govern purchasing, not personal data processing."]},
  {id:407,domain:A,question:"What is a security information and event management (SIEM) system's primary function?",options:["Encrypting logs in transit","Generating compliance reports","Running vulnerability scans","Correlating security events"],answer:3,explanation:"SIEMs aggregate events from firewalls, endpoints, applications, and cloud to detect patterns that individual tools cannot see in isolation.",optionExplanations:["Log encryption in transit is handled by TLS, not the SIEM's core role.","Compliance reporting is a secondary SIEM feature, not its primary function.","Vulnerability scanning is done by dedicated scanners, not SIEMs.","SIEMs collect, normalize, and correlate events from many sources to detect threats."]},
  {id:408,domain:T,question:"What is cross-site request forgery (CSRF)?",options:["Intercepting HTTP requests in transit","Stealing a victim's session cookies","Injecting scripts into web pages","Exploiting trust to forge requests"],answer:3,explanation:"CSRF exploits the browser's automatic inclusion of authentication cookies — a victim visiting a malicious site unknowingly triggers authenticated actions on another site.",optionExplanations:["Intercepting requests describes a man-in-the-middle attack, not CSRF.","Stealing cookies describes session hijacking, not CSRF.","Injecting scripts into pages describes XSS, not CSRF.","CSRF exploits a logged-in browser to submit unwanted authenticated requests."]},
  {id:409,domain:O,question:"What is an intrusion prevention system (IPS) and how does it differ from an IDS?",options:["Identical functions, different protocols","IPS software-only, IDS hardware-only","IDS alerts; IPS blocks","Roles reversed from the real definitions"],answer:2,explanation:"An IDS is passive (alerts only); an IPS is inline and active (detects and blocks). Both use signatures and anomaly detection but IPS can respond automatically.",optionExplanations:["The real distinction is active blocking versus passive alerting, not protocol differences.","Both IDS and IPS can be deployed as hardware or software.","An IDS monitors and alerts; an IPS sits inline and can block traffic.","This swaps the actual roles: IDS detects and alerts, IPS detects and prevents."]},
  {id:410,domain:G,question:"What is biometric authentication and its primary security risk?",options:["Device certificate authentication","Biometrics; can't be reset if breached","GPS location-based authentication","Behavioral typing-pattern authentication"],answer:1,explanation:"Fingerprints, iris scans, and face recognition authenticate uniquely but if compromised (database breach), users cannot get new fingerprints like they can new passwords.",optionExplanations:["Device certificates authenticate a machine, not a person's biological traits.","Biometrics are unique but immutable, so a breach permanently compromises them.","Location authentication relies on GPS or IP data, not biological traits.","Behavioral biometrics are a subtype; the main biometric risk is still permanence, not predictability."]},
  {id:411,domain:T,question:"What is a Trojan horse in cybersecurity?",options:["Self-replicating virus","Self-propagating network worm","Ransomware","Malware disguised as legitimate software"],answer:3,explanation:"Trojans rely on social engineering — users willingly install what appears to be useful software that secretly installs backdoors, RATs, or credential stealers.",optionExplanations:["Self-replication across files describes a virus, not a Trojan.","Autonomous network spread describes a worm, not a Trojan.","File-encrypting malware for payment describes ransomware, not a Trojan itself.","A Trojan appears legitimate while secretly performing malicious actions."]},
  {id:412,domain:A,question:"What is API security and why is it critical in modern architectures?",options:["Protecting APIs from abuse","Encrypting packets at the transport layer","Securing physical server rack access","Managing SSL certificate rotation"],answer:0,explanation:"APIs expose business logic and data directly — OWASP API Security Top 10 covers broken object level authorization, excessive data exposure, and injection attacks specific to APIs.",optionExplanations:["API security covers authentication, authorization, and input validation for app interfaces.","TLS encryption supports API security but doesn't address authorization or logic flaws.","Physical rack security is a data center control, not API security.","Certificate management supports secure communication but is narrower than full API security."]},
  {id:413,domain:O,question:"What is change management in IT security?",options:["Formal IT change approval process","Organizational restructuring","Updating employee access permissions","Managing source code version history"],answer:0,explanation:"Change management prevents outages and security incidents caused by unauthorized, poorly tested, or conflicting changes to production systems.",optionExplanations:["Change management governs modifications to production systems through review and approval.","Restructuring staff is an HR function, not change management.","Access updates are an identity management task, not change management itself.","Version control tracks code history; change management governs what reaches production."]},
  {id:414,domain:T,question:"What is a brute force attack?",options:["Trying every possible password or key","Physical attack on cabling","Exploiting a flaw to bypass authentication","Social engineering to get a password"],answer:0,explanation:"Brute force attacks are resource-intensive but guaranteed to succeed given time — countermeasures include account lockouts, CAPTCHAs, and rate limiting.",optionExplanations:["Brute force systematically tests combinations until the correct one is found.","Attacking physical infrastructure is unrelated to computational brute forcing.","Exploiting a vulnerability bypasses auth directly; brute force tests credentials instead.","Tricking a victim into giving up a password is phishing, not brute force."]},
  {id:415,domain:G,question:"What is steganography?",options:["Digital ownership watermarking","Data compression technique","Hiding data within ordinary files","Layered multi-algorithm encryption"],answer:2,explanation:"Steganography hides the existence of a message (vs. encryption which hides the meaning) — attackers use it to exfiltrate data hidden in images uploaded to public sites.",optionExplanations:["Watermarking proves ownership; steganography instead conceals a hidden message.","Compression reduces file size; steganography hides data without necessarily changing size.","Steganography hides messages in images, audio, or documents so their existence isn't suspected.","Multiple encryption layers is a different defense-in-depth technique, not concealment."]},
  {id:416,domain:P,question:"What is the difference between a data controller and a data processor under GDPR?",options:["Controller sets purpose and means","Controllers process; processors only store","Processors bear greater legal liability","Same entity, two job titles"],answer:0,explanation:"A hospital (controller) decides what patient data to collect; their cloud backup provider (processor) stores it per the hospital's instructions. Controllers bear primary GDPR responsibility.",optionExplanations:["A controller determines why and how data is processed; a processor acts on its behalf.","Both roles can perform processing and storage; the difference is who decides the purpose.","Controllers bear the primary GDPR responsibility, not processors.","Controller and processor are distinct legal roles with different obligations."]},
  {id:417,domain:A,question:"What is Defense in Depth?",options:["One impenetrable security layer","All resources spent on the perimeter","Multiple overlapping security layers","Military-grade encryption on all data"],answer:2,explanation:"Defense in depth assumes breaches will occur and ensures that no single point of failure can compromise the entire organization — multiple layers buy time for detection.",optionExplanations:["Relying on a single perfect layer contradicts the idea of defense in depth.","Focusing only on the perimeter is the outdated castle-and-moat model.","Defense in depth layers firewalls, endpoint protection, and monitoring so no single control failure is fatal.","Uniform strong encryption is just one possible layer, not the whole strategy."]},
  {id:418,domain:O,question:"What is vulnerability management?",options:["Tracking purchased software licenses","A once-a-year configuration review","Ongoing vulnerability remediation","Managing security team staffing"],answer:2,explanation:"Vulnerability management prioritizes remediation by risk severity, tracks remediation progress, and measures the organization's patch compliance over time.",optionExplanations:["License tracking is an asset management task, not vulnerability management.","Vulnerability management is continuous, not a single annual review.","Vulnerability management scans, prioritizes, and tracks remediation of security weaknesses over time.","Staffing decisions are an operations function, not vulnerability management."]},
  {id:419,domain:T,question:"What is an SQL injection attack?",options:["Inserting corrupted data records","Malicious SQL inserted into inputs","Escalating privileges via admin scripts","Flooding a database with queries"],answer:1,explanation:"SQL injection exploits applications that build queries by concatenating user input — attackers inject SQL that changes query logic to dump, modify, or delete data.",optionExplanations:["SQL injection changes query logic, not just raw data values.","SQL injection breaks out of the intended query using crafted input to alter its logic.","Privilege escalation may result from injection but isn't what the term describes.","Flooding a database with traffic describes a denial-of-service attack, not injection."]},
  {id:420,domain:G,question:"What is the principle of defense through diversity?",options:["Vendor diversity in controls","A unique algorithm per data type","A diverse security team's backgrounds","Storing data in several file formats"],answer:0,explanation:"Monocultures (same OS everywhere) create single points of failure — a single exploit can compromise all systems. Diversity limits the blast radius of any single vulnerability.",optionExplanations:["Diverse vendors mean one exploit can't defeat every layer at once.","Different algorithms per data type add complexity without a clear security benefit.","Team diversity is valuable but is not what this principle refers to.","Storing data in multiple formats doesn't improve control resilience."]},
  {id:421,domain:T,question:"What is a botnet?",options:["Peer-to-peer file-sharing network","Legitimate IT task automation network","Automated bots that monitor for threats","Network of hijacked computers"],answer:3,explanation:"Botnets are used for DDoS attacks, spam campaigns, credential stuffing, cryptomining, and proxy services — the botmaster profits while victims bear costs.",optionExplanations:["P2P file sharing is a legitimate network of willing participants, unlike a botnet.","Legitimate automation tools like Ansible aren't malware-controlled networks.","Defensive monitoring bots are legitimate tools, not compromised victim machines.","A botnet is a network of infected machines an attacker controls for coordinated attacks."]},
  {id:422,domain:A,question:"What is a secure software development lifecycle (SSDLC)?",options:["Reviewing code only after development","Integrating security into every dev phase","One test just before release","Restricting to pre-approved open-source components"],answer:1,explanation:"SSDLC (like Microsoft SDL or OWASP SAMM) integrates threat modeling, secure coding, SAST/DAST, and security training throughout development to reduce vulnerabilities.",optionExplanations:["Reviewing only after the fact is a bolt-on approach, not full SSDLC.","SSDLC integrates threat modeling, secure coding, and testing throughout development.","A single pre-release test is a narrower practice than the full SSDLC.","Restricting to vetted components is a procurement decision, not the full lifecycle."]},
  {id:423,domain:O,question:"What is a security risk register?",options:["Database of known software vulnerabilities","Log of past security incidents","Inventory of risks with likelihood, impact, and owners","List of approved security vendors"],answer:2,explanation:"Risk registers provide governance visibility into organizational risk posture, enabling prioritization of mitigation efforts and tracking progress over time.",optionExplanations:["A vulnerability database is technical; a risk register covers broader business risk.","An incident log records past events; a risk register tracks ongoing potential risks.","A risk register catalogs risks with scoring, ownership, and mitigation status.","A vendor list is a procurement record, not a risk tracking tool."]},
  {id:424,domain:T,question:"What is port scanning?",options:["Scanning outgoing documents for sensitive content","Probing ports to find open services","Scanning email ports for spam","Monitoring physical switch ports"],answer:1,explanation:"Port scanning (Nmap, Masscan) is reconnaissance that maps attack surface — identifying web servers, databases, SSH services, and other accessible services on a target.",optionExplanations:["Scanning outbound documents is a data loss prevention function, not port scanning.","Port scanning probes which ports are open to identify running services.","Spam filtering is an email security function, not port scanning.","Monitoring physical ports for rogue devices is a network access control function."]},
  {id:425,domain:G,question:"What is multi-factor authentication (MFA)?",options:["Multiple independent auth factors","Two sequential passwords","Approval from multiple administrators","Multiple security questions"],answer:0,explanation:"MFA dramatically reduces account takeover risk — even if credentials are stolen, attackers need the second factor (TOTP, hardware key, push notification) to gain access.",optionExplanations:["MFA combines factors like knowledge, possession, and inherence.","Multiple passwords are still one factor type: something you know.","Administrator approval is a workflow control, not a user authentication factor.","Security questions are all knowledge-based, so they don't provide true multi-factor security."]},
  {id:426,domain:P,question:"What is data minimization?",options:["Limiting which employees can view data","Collecting only necessary data","Anonymizing all data immediately","Compressing data to save storage"],answer:1,explanation:"Data minimization (GDPR Article 5) reduces privacy risk by limiting collection scope — data you don't collect cannot be breached or misused.",optionExplanations:["Limiting internal access is least privilege, not data minimization.","Data minimization means not collecting more personal data than the stated purpose needs.","Anonymization transforms data after collection; minimization limits what's collected up front.","Compression is a storage technique, unrelated to how much data is collected."]},
  {id:427,domain:A,question:"What is a cloud access security broker (CASB)?",options:["Internal security team run by the cloud provider","Cloud usage policy enforcement point","Cloud-hosted certificate authority","Authentication service for cloud apps"],answer:1,explanation:"CASBs provide visibility into shadow IT, enforce data loss prevention, detect threats in cloud apps, and apply compliance controls to cloud service usage.",optionExplanations:["A CASB is a customer-controlled layer, not an internal provider team.","A CASB sits between users and cloud services, enforcing visibility and control over usage.","A CA issues certificates for encryption; a CASB controls cloud service usage.","Identity providers handle authentication; a CASB enforces broader policy on top of that."]},
  {id:428,domain:O,question:"What is security awareness training?",options:["Training on specific security software tools","Teaching employees to recognize threats","Advanced training reserved for pentesters","Technical training for security engineers"],answer:1,explanation:"Humans are the most exploited attack vector — awareness training addresses phishing recognition, password hygiene, social engineering, and reporting suspicious activity.",optionExplanations:["Tool-specific training is narrow technical skill-building, not general awareness.","Awareness training covers phishing, social engineering, and safe practices for all staff.","Pentester training is specialized, not aimed at the general workforce.","Engineer-focused training is specialized and narrow, unlike general awareness training."]},
  {id:429,domain:T,question:"What is an exploit kit?",options:["Proof-of-concept exploits for authorized testing","Researcher documentation of known exploits","Automated browser-exploiting attack tool","Vendor tools for developing patches"],answer:2,explanation:"Exploit kits (RIG, Magnitude) check browser fingerprints and automatically deliver appropriate exploits — a single drive-by download visit can result in malware installation.",optionExplanations:["Authorized testing tools are legitimate research aids, unlike weaponized exploit kits.","Documentation toolkits are legitimate research, not automated attack platforms.","Exploit kits automatically detect and exploit browser flaws to deliver malware.","Patch development tools fix vulnerabilities; exploit kits attack them."]},
  {id:430,domain:G,question:"What is an access control list (ACL)?",options:["Rules permitting or denying actions","Approved software install list","List of permanently blocked websites","Registry tracking all user accounts"],answer:0,explanation:"ACLs on routers/firewalls control network traffic; ACLs on file systems control who can read, write, or execute files — both implement discretionary or mandatory access control.",optionExplanations:["ACLs define what traffic or actions are permitted on a device or object.","An approved software list is a whitelist, not an ACL.","A blocked site list is one possible ACL use, not the whole concept.","A user account registry is a directory service function, not an ACL."]},
  {id:431,domain:T,question:"What is spear phishing?",options:["Voice-call-based phishing","A marketing term with no real targeting","Mass, generic phishing to everyone","Highly targeted, personalized phishing"],answer:3,explanation:"Spear phishing uses reconnaissance (LinkedIn, social media, company website) to craft convincing lures — attackers know the victim's name, job, colleagues, and projects.",optionExplanations:["Voice-based phishing is vishing, a distinct technique.","The 'spear' name reflects precision targeting, not decorative branding.","Broad, generic campaigns describe mass phishing, not spear phishing.","Spear phishing uses researched personal details to make the lure convincing."]},
  {id:432,domain:A,question:"What is a load balancer from a security perspective?",options:["Distributing traffic across servers","Testing how much traffic a link handles","Throttling user or app bandwidth","Monitoring network performance and latency"],answer:0,explanation:"Load balancers improve resilience (no single server failure brings down the service) and can perform SSL offloading, WAF integration, and DDoS absorption.",optionExplanations:["Load balancers improve resilience and enable centralized security controls like SSL offloading.","Load testing tools assess capacity before deployment; load balancers handle live traffic.","Bandwidth throttling is a QoS function, not load balancing.","Performance monitoring uses dedicated tools; load balancers actively route traffic."]},
  {id:433,domain:O,question:"What is the purpose of log retention policies?",options:["Moving logs to tape on a schedule","Standardizing the log message format","Deleting logs as quickly as possible","Defining log retention periods"],answer:3,explanation:"Log retention must balance regulatory requirements (PCI DSS: 1 year, HIPAA: 6 years) with storage costs and investigation needs — logs deleted too early lose forensic value.",optionExplanations:["Archiving to tape is a storage implementation detail, not the retention policy itself.","Format standardization is a logging configuration issue, not retention.","Deleting logs quickly undermines investigations, the opposite of good retention.","Retention policies set how long logs are kept to support compliance and forensics."]},
  {id:434,domain:T,question:"What is a pass-the-hash attack?",options:["Engineering hash collisions","Reusing a stolen hash to log in","Transferring a file's hash for verification","Intercepting hash values sent in cleartext"],answer:1,explanation:"Windows NTLM allows authentication with the hash directly — attackers extract hashes from memory (using Mimikatz) and use them for lateral movement.",optionExplanations:["Collision engineering is a separate forgery technique, not pass-the-hash.","Pass-the-hash reuses a stolen NTLM hash to authenticate without cracking the password.","Transferring file hashes for integrity checks is unrelated to authentication attacks.","This describes network interception, not reuse of an already-captured hash."]},
  {id:435,domain:G,question:"What is a digital certificate?",options:["A hashed, stored password","A signature applied to one document","A CA-signed document binding a key to an identity","A scanned business license"],answer:2,explanation:"Digital certificates (X.509 standard) establish trusted identity for HTTPS, code signing, email encryption, and VPN authentication by binding public keys to verified identities.",optionExplanations:["A hashed password is an authentication secret, not a certificate.","A single document signature is narrower than the full certificate concept.","A digital certificate binds a public key to a verified identity via a CA signature.","A business license is a legal document, unrelated to cryptographic identity."]},
  {id:436,domain:P,question:"What is anonymization vs. pseudonymization?",options:["Pseudonymization is stronger than anonymization","Anonymization required by GDPR; pseudonymization is not","Same irreversible transformation","Anonymization removes identifiers permanently; pseudonymization uses reversible aliases"],answer:3,explanation:"GDPR considers anonymized data outside scope; pseudonymized data is still personal data since re-identification is possible. Pseudonymization reduces risk but doesn't eliminate privacy obligations.",optionExplanations:["Anonymization actually offers the stronger protection of the two.","GDPR applies regardless of method; anonymized data alone falls outside its scope.","The two processes are distinct, not identical or interchangeable.","Anonymized data can't be re-linked; pseudonymized data can be re-identified via a key."]},
  {id:437,domain:A,question:"What is a network access control (NAC) system?",options:["A set of firewall traffic rules","Checks device compliance first","A physical lock on switches","A protocol allowlist for a segment"],answer:1,explanation:"NAC (802.1X, Cisco ISE) checks device health (patching, AV, certificates) before allowing network access, quarantining non-compliant devices to a remediation VLAN.",optionExplanations:["Firewall rules control traffic between connected networks, not connection eligibility.","NAC checks device posture, like patch level and antivirus status, before granting access.","A physical lock is a physical security control, not NAC.","A protocol allowlist is a network policy configuration, not device authentication."]},
  {id:438,domain:O,question:"What is the kill chain in cybersecurity?",options:["A technique to kill malicious processes","A list of one malware family's commands","A method for forensic evidence collection","Framework of attack stages"],answer:3,explanation:"Lockheed Martin's Cyber Kill Chain (Reconnaissance→Weaponization→Delivery→Exploitation→Installation→C2→Actions on Objectives) helps defenders understand and break attack sequences.",optionExplanations:["Stopping processes is an incident response action, not the kill chain concept.","Malware command lists are specific threat intel, not the general kill chain model.","Evidence collection is forensic methodology, distinct from the kill chain framework.","The kill chain breaks an attack into stages so defenders can disrupt it at any point."]},
  {id:439,domain:T,question:"What is a side-channel attack?",options:["Exploiting timing or power use","Physically plugging into network ports","Targeting backup systems specifically","Social engineering through a third party"],answer:0,explanation:"Timing attacks measure computation time to determine key bits; power analysis watches power consumption during crypto operations — these bypass mathematical security.",optionExplanations:["Side channels measure physical traits like timing or power draw during crypto operations.","Physical port access is standard network infrastructure, not a side channel.","Targeting backups is a persistence strategy, not a physical measurement attack.","Third-party social engineering is a pretexting tactic, not a side-channel attack."]},
  {id:440,domain:G,question:"What is the difference between authentication and authorization?",options:["Authorization occurs before authentication","Authentication technical; authorization non-technical","Same process, interchangeable terms","Authentication verifies identity; authorization determines permissions"],answer:3,explanation:"Authentication proves who you are (username/password, MFA); authorization determines your access rights (can this user read this file, access this API endpoint?).",optionExplanations:["Authentication must occur before authorization, not the reverse.","Both are technical processes enforced by systems, not one technical and one purely policy.","Treating them as the same term leads to access control design errors.","You prove who you are first, then the system checks what you're allowed to do."]},
  {id:441,domain:T,question:"What is click fraud in the context of cybersecurity?",options:["Bots clicking ads to drain budgets","Identity theft via fake login buttons","Any fraud from clicking phishing links","Fake buttons that lure clicks on a page"],answer:0,explanation:"Click fraud botnets generate fake ad clicks — advertisers pay for worthless clicks (competitor sabotage) or publishers generate fraudulent revenue.",optionExplanations:["Click fraud uses bots to fake ad clicks, costing advertisers money.","Fake login forms describe credential phishing, not click fraud.","General phishing link clicks aren't click fraud, which specifically targets ad billing.","Fake buttons for stealing credentials describe phishing or clickjacking, not click fraud."]},
  {id:442,domain:A,question:"What is a deception technology platform?",options:["Decoys and traps to detect attackers","Deceptive advertising claims","Deepfake detection technology","Social engineering training simulator"],answer:0,explanation:"Deception technology goes beyond honeypots — it plants fake credentials, files, and systems throughout the real environment to detect and mislead attackers.",optionExplanations:["Deception platforms plant fake assets that alert security when attackers interact with them.","Misleading advertising is a consumer protection issue, unrelated to deception technology.","Deepfake detection addresses media authenticity, not attacker detection.","Training simulators test employees; deception tech misleads real attackers in production."]},
  {id:443,domain:O,question:"What is a security audit?",options:["An automated vulnerability scan","Formal review of controls","A performance test of IT systems","A review of employee access rights"],answer:1,explanation:"Security audits provide independent verification that controls exist and work — they examine policies, test controls, interview staff, and review evidence against a standard.",optionExplanations:["A scan is a narrow automated tool, not a full audit.","An audit evaluates controls against a framework through review, testing, and interviews.","Performance testing measures speed and capacity, not security control adequacy.","Access review is one narrow audit activity, not the full security audit scope."]},
  {id:444,domain:T,question:"What is BGP hijacking?",options:["Manipulating BGP routes to redirect traffic","A fabricated 'Border Gateway Patrol' attack","Hijacking encrypted sessions between BGP routers","Gaining admin control of one router"],answer:0,explanation:"BGP hijacking announces false route information, redirecting traffic through attacker infrastructure for interception, blackholing, or traffic analysis.",optionExplanations:["BGP hijacking announces false routes to redirect internet traffic through attacker infrastructure.","There's no such agency; BGP stands for Border Gateway Protocol, a real routing protocol.","Session encryption is a mitigation; hijacking attacks the route announcement trust model itself.","Taking over a single router is device-level compromise, not a routing-protocol attack."]},
  {id:445,domain:G,question:"What is public key infrastructure (PKI)?",options:["A government-only key management system","Certificate management framework","A public database of everyone's keys","A system for managing SSH keys"],answer:1,explanation:"PKI enables trust at scale — CAs vouch for public key ownership, browsers trust CA-signed certificates, enabling secure HTTPS worldwide.",optionExplanations:["PKI can be run by governments or private companies alike.","PKI includes CAs, policies, and revocation infrastructure supporting certificate-based trust.","Key servers store keys for lookup; PKI verifies key ownership through signed certificates.","SSH key management is a separate, narrower concern from certificate-based PKI."]},
  {id:446,domain:P,question:"What is the purpose of a privacy notice?",options:["A binding contract with users","A warning about a future data breach","Notice explaining data practices","Internal policy for handling coworker data"],answer:2,explanation:"Privacy notices (required by GDPR Article 13/14) must be concise, transparent, and provided at the time of data collection — they enable informed consent.",optionExplanations:["Binding contracts are terms of service, not a privacy notice.","Breach warnings might appear, but that isn't a notice's core purpose.","Privacy notices explain collection, purpose, and individual rights at the point of collection.","Internal handling policies guide employees, while notices inform external data subjects."]},
  {id:447,domain:A,question:"What is the purpose of network traffic analysis (NTA)?",options:["Detecting anomalies in traffic","Monitoring employee internet use","Tracking network topology changes","Optimizing bandwidth allocation"],answer:0,explanation:"NTA (using tools like Darktrace, ExtraHop, Vectra) establishes behavioral baselines and alerts on deviations — finding attackers who evade signature-based detection.",optionExplanations:["NTA baselines behavior and flags anomalies like C2 traffic or unusual transfers.","Productivity monitoring is an HR function, not a security detection capability.","Topology tracking is network housekeeping, not real-time threat analysis.","Bandwidth optimization is a performance function, not security threat detection."]},
  {id:448,domain:O,question:"What is penetration testing methodology?",options:["Unstructured hacking with no planning","Fully automated scanning, no analyst","Defined phases from recon to report","Recurring annual compliance audit"],answer:2,explanation:"Pentest methodology (defined in PTES, OWASP, NIST 800-115) ensures comprehensive coverage, reproducibility, and actionable reporting of discovered vulnerabilities.",optionExplanations:["Unstructured attempts lack scope and authorization, unlike a defined methodology.","Scanning finds weaknesses without exploiting them; pentesting actively exploits and validates impact.","Pentest methodology follows defined phases from reconnaissance through reporting.","Annual audits are compliance-driven; pentesting actively simulates attacker techniques."]},
  {id:449,domain:T,question:"What is a birthday attack in cryptography?",options:["Using a victim's birthdate in social engineering","An attack timed to an anniversary date","Exploiting the birthday paradox to find hash collisions","A timing attack on key generation"],answer:2,explanation:"The birthday paradox means collision probability is much higher than intuition suggests — finding any two matching hash inputs requires only ~2^(n/2) attempts vs. 2^n.",optionExplanations:["Using a birthdate for pretexting is OSINT-driven social engineering, not a birthday attack.","Birthday attacks exploit probability theory, not actual calendar dates.","The birthday paradox makes hash collisions far easier to find than brute force suggests.","Timing attacks leak secrets via computation duration, a different technique entirely."]},
  {id:450,domain:G,question:"What is a hardware root of trust?",options:["Blind trust in hardware vendors","Hardware certified by a trusted authority","Hardware-based boot and key trust","A physical key to a server room"],answer:2,explanation:"Hardware roots of trust (TPM, Intel TXT, ARM TrustZone) enable measured boot, device attestation, and secure key storage — providing trust that cannot be undermined by software.",optionExplanations:["Implicit vendor trust is a supply chain risk, not a root of trust itself.","Vendor certification is a supply-chain step, not the on-device trust anchor.","A hardware root of trust verifies boot integrity and protects keys in tamper-resistant hardware.","A physical door key is a facility control, unrelated to cryptographic trust."]},
  {id:451,domain:T,question:"What is a typosquatting attack?",options:["Registering misspelled lookalike domains","Typing malicious code quickly to evade analysis","Fake keyboard shortcut mappings","Physically trespassing in a data center"],answer:0,explanation:"Typosquatters register 'gooogle.com', 'paypa1.com', etc., capturing mistyped traffic and serving phishing pages, malware, or ads to unknowing victims.",optionExplanations:["Typosquatting registers domains close to real ones to catch mistyped URLs.","Typing speed has no bearing on detection evasion or domain registration.","Keyboard shortcuts are legitimate OS features, unrelated to domain typos.","Physical trespassing is a facility security issue, not a domain-based attack."]},
  {id:452,domain:A,question:"What is secure boot?",options:["Verifying boot component signatures","Encrypting the drive before the OS loads","Requiring admin authentication to boot","Protecting the boot process physically only"],answer:0,explanation:"Secure Boot (UEFI feature) verifies each component in the boot chain is signed by a trusted key — preventing bootloader-level malware (bootkits) from persisting.",optionExplanations:["Secure Boot checks cryptographic signatures on each boot component before it runs.","Drive encryption protects stored data; Secure Boot verifies boot code integrity.","Admin login at boot is a separate feature from automated signature verification.","Physical security alone doesn't verify boot code integrity the way Secure Boot does."]},
  {id:453,domain:O,question:"What is security orchestration?",options:["Managing security project schedules","Linking tools into automated workflows","Planning employee awareness training","Restructuring the security team hierarchy"],answer:1,explanation:"Security orchestration (in SOAR platforms) integrates SIEM, EDR, threat intelligence, ticketing, and firewalls to execute playbooks spanning multiple tools automatically.",optionExplanations:["Project scheduling is general management, not tool orchestration.","Orchestration connects tools via APIs so an alert can trigger automated responses.","Awareness training targets employees, not automated tool integration.","Team hierarchy is an organizational design choice, not orchestration."]},
  {id:454,domain:T,question:"What is a replay attack?",options:["An attack on a recording device","Reusing captured data to gain access","Repeating a social engineering script","Replaying logs to reconstruct an attack"],answer:1,explanation:"Replay attacks reuse captured authentication tokens or transactions — prevented by timestamps, nonces, and sequence numbers that make captured data invalid for retransmission.",optionExplanations:["Attacking recording hardware is unrelated to network replay attacks.","Replay attacks capture and resend valid tokens or transactions to impersonate a user.","Reusing a social engineering script is a human tactic, not a data replay.","Reviewing logs afterward is forensic reconstruction, not the attack itself."]},
  {id:455,domain:G,question:"What is the purpose of a Certificate Authority (CA)?",options:["Entity issuing network access certificates","Verifies identity, issues certificates","Entity tracking software licenses","Provider supplying encryption keys to users"],answer:1,explanation:"CAs form the trust hierarchy of PKI — browsers ship with trusted root CA lists; organizations can also run private CAs for internal certificate management.",optionExplanations:["Network access certificates may rely on a CA, but the CA itself is the trust anchor.","A CA validates identity and binds it to a public key in a signed certificate.","Software license tracking is unrelated to cryptographic identity issuance.","CAs bind existing public keys to identities; they don't hand out keys directly."]},
  {id:456,domain:P,question:"What is purpose limitation in data privacy?",options:["Deleting data after a retention period","Data collected only for a stated purpose","Restricting data access to authorized staff","Limiting collection to certain regions"],answer:1,explanation:"GDPR Article 5(1)(b) requires data be collected for specific purposes — using customer data collected for order fulfillment for marketing requires new consent.",optionExplanations:["Time-based deletion is a retention rule, not purpose limitation.","Purpose limitation restricts data use to the reasons stated at collection.","Staff access restriction is least privilege, not purpose limitation.","Geographic restrictions relate to data residency, not the purpose of collection."]},
  {id:457,domain:A,question:"What is a virtual private network (VPN)?",options:["Isolated internal virtual network segment","Encrypted tunnel for secure remote access","Software-defined networking without cables","A private-IP virtual machine instance"],answer:1,explanation:"VPNs encrypt traffic end-to-end (IPsec site-to-site or SSL/TLS remote access), securing communications over untrusted networks like public WiFi or the internet.",optionExplanations:["Hypervisor-internal segments isolate compute, unlike remote VPN access.","A VPN encrypts traffic between endpoints, securing access over public networks.","SDN virtualizes network functions but still relies on physical infrastructure.","A VM with a private IP is compute isolation, not a network tunneling technology."]},
  {id:458,domain:O,question:"What is a post-mortem (lessons learned) in incident response?",options:["A report submitted to law enforcement","A medical autopsy procedure","A catalog of destroyed systems","A structured review of what happened and how to improve"],answer:3,explanation:"Post-mortems identify gaps in detection, response time, communication, and playbooks — converting negative experiences into organizational security improvements.",optionExplanations:["Law enforcement reporting is a separate obligation, not the post-mortem itself.","The medical term is used only as a metaphor here for a retrospective review.","Cataloging damage is part of impact assessment, not the full lessons-learned process.","Post-mortems review the timeline, response effectiveness, and needed improvements."]},
  {id:459,domain:T,question:"What is an advanced persistent threat (APT)?",options:["An automated botnet malware campaign","Long-term targeted intrusion","A next-gen firewall for DDoS defense","A recurring failed software update"],answer:1,explanation:"APT groups (APT28/Fancy Bear, APT41) conduct targeted espionage, intellectual property theft, or sabotage — maintaining access for months or years while avoiding detection.",optionExplanations:["Automated campaigns are typically broad and opportunistic, unlike a targeted APT.","APTs are well-funded, persistent intrusions aimed at specific strategic objectives.","Firewalls are defensive devices, not the attacker groups APTs describe.","Failed update installs are an IT operations issue, unrelated to APTs."]},
  {id:460,domain:G,question:"What is the principle of separation of duties?",options:["Dividing tasks so no one person acts alone","Isolated systems per business unit","Separate security and IT departments","Separate dev, staging, and production environments"],answer:0,explanation:"Separation of duties prevents insider fraud — in finance, the person who approves payments shouldn't also be the person who processes them or reconciles accounts.",optionExplanations:["Separation of duties splits sensitive tasks so fraud requires collusion.","System isolation per unit is data segregation, not task division.","Reporting-line separation may support SoD but isn't its core definition.","Environment separation prevents unauthorized changes but isn't the SoD principle itself."]},
  {id:461,domain:O,question:"What is a disaster recovery plan (DRP)?",options:["IT systems recovery plan","A fire evacuation procedure","Restoring deleted files from backup","A high-level business continuity plan"],answer:0,explanation:"DRPs specify recovery procedures, responsible parties, RTOs/RPOs, and restoration steps for specific scenarios — they must be regularly tested to be effective.",optionExplanations:["A DRP details how to restore IT infrastructure and data after disruptive events.","Fire evacuation is a physical safety plan, not IT recovery.","File restoration is one scenario a DRP covers, not its full scope.","Business continuity covers the whole organization; a DRP focuses specifically on IT recovery."]},
  {id:462,domain:T,question:"What is a watering hole attack's key advantage over spear phishing?",options:["Reaches a broader victim population","Works without any victim internet access","Uses more advanced browser exploits","Victim comes to a trusted site"],answer:3,explanation:"Watering hole attacks compromise sites victims already trust and visit regularly — unlike suspicious emails, visiting a trusted website doesn't trigger security awareness alarms.",optionExplanations:["Watering holes are actually more targeted, not broader, than generic phishing.","The attack still requires the victim to reach an internet-accessible site.","Both attack types can use sophisticated exploits; that isn't the key advantage.","Victims trust the site they visit, making them less suspicious than with email."]},
  {id:463,domain:A,question:"What is role-based access control (RBAC)?",options:["Vetting users through mock scenarios","Granting access based on predefined job roles","Controlling access by physical location","Managers approving each request individually"],answer:1,explanation:"RBAC simplifies access management — instead of configuring per-user permissions, administrators manage roles, and users inherit permissions from their assigned roles.",optionExplanations:["Competency tests are training assessments, not RBAC's access model.","RBAC assigns permissions to roles and users inherit them from their assigned role.","Physical workspace roles are a physical access control, not RBAC.","Case-by-case manager approval describes a discretionary model, not RBAC."]},
  {id:464,domain:P,question:"What is the difference between a privacy policy and a privacy notice?",options:["Synonymous, interchangeable terms","Policy is internal governance; notice is external communication","Policy is binding; notice is voluntary","Notice is internal; policy is external"],answer:1,explanation:"Privacy policies govern internal processes; privacy notices (also called privacy statements) are the public-facing communications required by regulations like GDPR.",optionExplanations:["Conflating the two terms is a common compliance error.","The policy guides internal practice; the notice informs external data subjects.","Privacy notices are legally required under GDPR, not merely voluntary.","This reverses the actual audiences: notices are external, policies are internal."]},
  {id:465,domain:O,question:"What is a threat intelligence feed?",options:["A stream of current IoCs and threat data","Government cybersecurity advisories","Alerts generated by internal SIEM or IDS tools","A security news blog or social feed"],answer:0,explanation:"Threat intelligence feeds (AlienVault OTX, MISP, commercial feeds) provide IoCs (malicious IPs, domains, file hashes) that can be ingested into SIEM, firewalls, and EDR for automated blocking.",optionExplanations:["Threat intel feeds deliver machine-readable IoCs that tools can act on automatically.","Government advisories are one source; feeds are broader and more automated.","Internal alerts come from your own tools, not external threat intelligence.","News aggregation is informational awareness, not structured operational data."]},
  {id:466,domain:T,question:"What is credential harvesting?",options:["Securely storing credentials in a vault","Analyzing breach dumps for research","Stolen credentials via phishing","Provisioning new employee passwords"],answer:2,explanation:"Credential harvesters use fake login pages, keyloggers, password stealers, and breach databases to collect credentials for account takeover and lateral movement.",optionExplanations:["Vault storage is secure credential management, the opposite of harvesting.","Research analysis of breach data is threat intelligence work, not harvesting.","Credential harvesting collects login data through phishing, malware, or breach data for unauthorized access.","Issuing new employee credentials is IT provisioning, not an attacker activity."]},
  {id:467,domain:G,question:"What is the purpose of a Trusted Platform Module (TPM)?",options:["An approved software vendor list","A sandbox for security testing","Chip managing keys and secure boot","A portable security key or smart card"],answer:2,explanation:"TPM 2.0 enables BitLocker drive encryption key protection, Secure Boot, device health attestation, and is required for Windows 11 — providing hardware-anchored security.",optionExplanations:["Vendor allowlists are a software policy control, not a hardware chip.","Testing sandboxes are software QA tools, not a hardware security chip.","A TPM generates and protects keys and measures boot integrity in dedicated hardware.","Portable tokens are external MFA devices; a TPM is built into the device itself."]},
  {id:468,domain:A,question:"What is attribute-based access control (ABAC)?",options:["File permissions based on file metadata","MFA requiring multiple identity attributes","RBAC with added verification steps","Attribute-based access decisions"],answer:3,explanation:"ABAC can express policies like 'a physician can access patient records from hospital-approved devices during working hours in clinical locations' — far more expressive than RBAC.",optionExplanations:["File metadata permissions are a basic OS model, not the full ABAC concept.","MFA verifies identity; ABAC is an authorization model applied after authentication.","ABAC is a distinct, more flexible model, not simply RBAC plus verification.","ABAC evaluates user, resource, and environmental attributes together to decide access."]},
  {id:469,domain:O,question:"What is a security gap analysis?",options:["Comparing controls to a framework","Evaluating network throughput against SLAs","Assessing physical security coverage","Identifying perimeter firewall coverage gaps"],answer:0,explanation:"Gap analyses compare current security state against frameworks (NIST CSF, ISO 27001, CIS Controls) to create prioritized roadmaps for security program improvement.",optionExplanations:["A gap analysis maps controls to a framework and prioritizes remediation.","Throughput evaluation is capacity planning, not a security gap analysis.","Physical coverage review is one narrow component, not the full program analysis.","Perimeter gaps are one component of a much broader security gap analysis."]},
  {id:470,domain:T,question:"What is a drive-by download attack?",options:["A fake software update trick","Malware installed just by visiting a malicious site","A trojanized document with malicious macros","USB autorun malware"],answer:1,explanation:"Drive-by downloads exploit browser or plugin vulnerabilities (Java, Flash, PDF reader) — simply visiting a page installs malware without clicks or downloads.",optionExplanations:["Fake updates require the user to download and run them, unlike a drive-by.","Drive-by downloads install automatically when a browser or plugin flaw is exploited.","Trojanized files require the user to open them, unlike a drive-by download.","USB autorun malware needs physical media, unlike a purely web-based drive-by."]},
  {id:471,domain:G,question:"What is a key derivation function (KDF)?",options:["A key exchange protocol like Diffie-Hellman","A function deriving keys from a secret using iteration and salt","An asymmetric key pair generation algorithm","Formatting random bytes into key material"],answer:1,explanation:"KDFs like PBKDF2, bcrypt, and Argon2 are deliberately slow — iteration counts make brute force infeasible even with fast hardware like GPUs.",optionExplanations:["Key exchange protocols establish shared secrets; KDFs derive keys from an existing secret.","KDFs stretch a low-entropy secret like a password into a strong key using salted iterations.","Asymmetric key generation produces public/private pairs, a different process from a KDF.","KDFs derive keys from a secret input rather than just formatting random bytes."]},
  {id:472,domain:P,question:"What is the privacy by default principle?",options:["Privacy settings applied only to default accounts","Settings public by default, requiring opt-out","Minimum data processed by default, users opt in","Data collected fully by default unless opted out"],answer:2,explanation:"GDPR Article 25 requires privacy by default — when launching a social network, privacy should be maximum by default, not exposing profiles to everyone unless users choose to.",optionExplanations:["Privacy by default applies to all accounts and configurations, not a subset.","Public-by-default settings maximize exposure, the opposite of this principle.","Privacy by default means minimal data processing until the user actively opts in.","Maximum data collection by default is the opposite of privacy by default."]},
  {id:473,domain:A,question:"What is security-as-code?",options:["Automated compliance reporting scripts","Static code scanning for vulnerabilities","Security controls expressed as code","Writing code per secure coding standards"],answer:2,explanation:"Security-as-code enables policy drift detection, peer review of security configurations, and automated enforcement — bringing software engineering rigor to security operations.",optionExplanations:["Automated reporting is one useful capability, not the whole concept.","Code scanning is static application testing, a narrower practice than security-as-code.","Security-as-code expresses configurations and policies as code for review and automated enforcement.","Secure coding practices are about writing safe code, not codifying security infrastructure itself."]},
  {id:474,domain:O,question:"What is mean time to respond (MTTR) in security operations?",options:["Time from disclosure to patch deployment","Time from vulnerability report to vendor patch","Time for help desk to resolve tickets","Detection-to-recovery response time"],answer:3,explanation:"MTTR measures response effectiveness — lower MTTR reduces attacker dwell time and damage. SOAR automation is a primary way to reduce MTTR.",optionExplanations:["Patch deployment time is tracked separately as mean time to patch.","Vendor disclosure timelines are a different vulnerability management metric.","Ticket resolution time is a customer service metric, not MTTR.","MTTR measures the security team's speed from detection through containment and recovery."]},
  {id:475,domain:T,question:"What is homograph attack (IDN homograph attack)?",options:["Hidden text embedded in documents","English-language homographs to evade filters","Exploiting graph-based detection tools","Unicode look-alike domain names"],answer:3,explanation:"Internationalized domain name (IDN) homograph attacks use Cyrillic 'а' instead of Latin 'a' — 'apple.com' and 'аpple.com' look identical but point to different servers.",optionExplanations:["Hidden document text is a data concealment technique, not a homograph attack.","Linguistic homographs are a wordplay concept, unrelated to Unicode domain spoofing.","Graph-tool exploitation is a distinct attack category, not IDN spoofing.","Homograph attacks register domains using Unicode characters visually identical to Latin ones."]},
  {id:476,domain:G,question:"What is certificate pinning?",options:["Organizing certificate files by folder","Scheduling certificate renewal reminders","Displaying certificates on a bulletin board","App hardcodes expected certificate data"],answer:3,explanation:"Certificate pinning prevents MitM attacks using rogue CA-signed certificates — mobile banking apps pin their server certificate so attackers can't intercept with their own valid certificate.",optionExplanations:["File organization is an administrative task, not a security control.","Renewal reminders support lifecycle management but aren't pinning itself.","Physical display is an informal check, not an application-level control.","Pinning embeds expected certificate details so unmatched certificates are rejected, even if validly signed."]},
  {id:477,domain:A,question:"What is east-west traffic in network security?",options:["WAN traffic between branch offices","Lateral server-to-server traffic","Traffic routed between geographic regions","Email routing paths"],answer:1,explanation:"Most intrusion detection focuses on north-south (perimeter) traffic; attackers use east-west movement (lateral movement) to reach valuable targets inside the network.",optionExplanations:["Branch-to-branch WAN traffic is a different flow than east-west traffic.","East-west traffic flows laterally between internal servers, unlike north-south internet traffic.","Geographic routing is unrelated to the east-west/north-south traffic distinction.","Email routing is a messaging concept, not a network traffic direction."]},
  {id:478,domain:O,question:"What is the purpose of security metrics?",options:["Quantifiable measures of security program effectiveness","A monthly incident count","Network throughput and latency stats","Time security staff spend on tasks"],answer:0,explanation:"Security metrics (patch compliance %, MTTD, vulnerability density, phishing click rates) enable data-driven security management and demonstrate value to executive leadership.",optionExplanations:["Security metrics quantify effectiveness and risk to support data-driven decisions.","Incident counts are one basic metric, not the full scope of a metrics program.","Network performance stats are operational, not security effectiveness metrics.","Staff time tracking is an operational measure, not a security effectiveness metric."]},
  {id:479,domain:T,question:"What is a man-in-the-middle (MitM) attack?",options:["Exploiting middleware software vulnerabilities","Social engineering via a trusted intermediary","Secretly intercepting private communications","Physical positioning between network devices"],answer:2,explanation:"MitM attacks (via ARP poisoning, rogue APs, SSL stripping) allow attackers to read, modify, and inject traffic — defeated by proper certificate validation and encryption.",optionExplanations:["Middleware exploitation targets application infrastructure, not the communication channel itself.","Using an intermediary for fraud is a social engineering tactic, not a technical MitM.","A MitM attacker secretly intercepts and can alter traffic between two parties.","Physical proximity isn't required; MitM attacks can work remotely over a network."]},
  {id:480,domain:G,question:"What is the concept of least privilege?",options:["Elevated access only during maintenance windows","Granting only the minimum permissions needed","Choosing the cheapest security tools","Minimizing security staff salaries"],answer:1,explanation:"Least privilege limits damage from compromised accounts, insider threats, and malware — a compromised standard user account can't modify system files they have no business accessing.",optionExplanations:["Time-limited elevation is just-in-time access, a related but different concept.","Least privilege grants only the permissions required to do a job, nothing more.","Cost optimization is a budget decision, unrelated to the least privilege principle.","Salary decisions are an HR matter, not a security design principle."]},
  {id:481,domain:T,question:"What is adversarial machine learning?",options:["Training a model on historical attack data","ML applied to competitive business analytics","AI simulating adversary behavior for training","Techniques to deceive or poison ML models"],answer:3,explanation:"Adversarial ML attacks include model poisoning (corrupting training data), evasion (inputs that fool classifiers), and model inversion (extracting training data from models).",optionExplanations:["Training defensive models on attack data improves detection, unlike adversarial ML attacks.","Business analytics using ML is a data science application, not a security concern.","AI-driven adversary simulation is a training tool, not an attack on ML itself.","Adversarial ML covers crafted inputs and poisoned data that manipulate models."]},
  {id:482,domain:A,question:"What is a privileged access workstation (PAW)?",options:["A laptop with local admin rights","A developer workstation with elevated access","A hardened workstation used only for admin tasks","A workstation shared by multiple admins"],answer:2,explanation:"PAWs are separate from regular workstations — no internet browsing, no email, minimal software — so attackers can't steal admin credentials through phishing or drive-by downloads.",optionExplanations:["A regular admin laptop lacks the isolation and hardening a PAW requires.","Developer workstations support coding tasks, unlike a dedicated admin-only PAW.","A PAW is isolated and hardened, used exclusively for privileged administrative work.","Sharing a PAW between admins undermines accountability and session isolation."]},
  {id:483,domain:O,question:"What is a cybersecurity framework?",options:["Legally mandated industry requirements","A programming library for security tools","A rack-mount hardware system","Guidelines and standards for managing security risk"],answer:3,explanation:"Frameworks (NIST CSF, ISO 27001, CIS Controls) provide structured approaches to building and maturing security programs — enabling consistent risk management.",optionExplanations:["Frameworks are often voluntary guidance, unlike legally mandated regulations.","Coding libraries are development tools, not organizational risk guidance.","Rack-mount systems are physical infrastructure, unrelated to a risk framework.","A cybersecurity framework provides structured guidance for managing organizational risk."]},
  {id:484,domain:T,question:"What is a polymorphic malware?",options:["Malware compiled in multiple languages","Malware attacking many targets at once","Malware combining several attack techniques","Malware that mutates to evade detection"],answer:3,explanation:"Polymorphic malware mutates with each infection (using encryption with variable keys, code rearrangement) — its signature never appears twice, defeating traditional antivirus.",optionExplanations:["Multi-language builds are a development trait, not code mutation.","Attacking many targets describes campaign scope, not polymorphism.","Combining techniques describes a multi-vector attack, not code mutation.","Polymorphic malware changes its signature with each copy while keeping its function."]},
  {id:485,domain:G,question:"What is a nonce in cryptography?",options:["A meaningless filler value","A number used once to ensure uniqueness","Repeated hashing to slow brute force","A hash function configuration parameter"],answer:1,explanation:"Nonces in TLS handshakes, TOTP tokens, and challenge-response authentication ensure each session or operation is unique — preventing attackers from reusing captured values.",optionExplanations:["Nonces are not meaningless; they prevent replay by ensuring uniqueness.","A nonce ensures each cryptographic operation or session produces a unique result.","Iterative hashing for work factor is key stretching, a different concept from a nonce.","Hash configuration parameters control algorithm behavior, not single-use uniqueness."]},
  {id:486,domain:P,question:"What is the purpose of a data protection officer (DPO)?",options:["A role overseeing GDPR compliance","An IT role managing data backups","A role protecting trade secrets","An investigator of confirmed data breaches"],answer:0,explanation:"GDPR Article 37 requires DPOs for public authorities and organizations with large-scale personal data processing — they advise, monitor compliance, and liaise with data protection authorities.",optionExplanations:["A DPO advises on compliance, monitors GDPR obligations, and liaises with regulators.","Backup and recovery is an IT operations role, not the DPO's function.","Protecting trade secrets is a business intelligence function, not the DPO role.","Breach investigation may involve a DPO, but it isn't their primary ongoing role."]},
  {id:487,domain:A,question:"What is network topology and why does it matter for security?",options:["Physical arrangement of network cables","Arrangement of elements determining data flow and control placement","Rack mounting arrangement of hardware","A visual diagram of the network"],answer:1,explanation:"Security controls must be placed where they can inspect all relevant traffic — topology determines if a firewall actually sees traffic or if there are paths around it.",optionExplanations:["Cabling is one physical layer of topology, not the full logical picture.","Topology determines which systems interconnect and where security controls belong.","Rack layout is physical organization, distinct from the logical topology concept.","A diagram represents topology visually; topology itself is the actual structure of connections."]},
  {id:488,domain:O,question:"What is continuous security monitoring (CSM)?",options:["Monthly configuration reviews","Physical guards monitoring facilities","Scheduled simulated attacks","Continuous automated monitoring"],answer:3,explanation:"CSM (NIST SP 800-137) implements automation to continuously collect metrics, perform change detection, and report security status — replacing periodic point-in-time assessments.",optionExplanations:["Monthly reviews are periodic snapshots, unlike continuous monitoring.","Physical guards monitor facilities, not IT security posture continuously.","Simulated attacks are periodic pentests, not ongoing automated monitoring.","CSM continuously collects and analyzes data for near-real-time visibility."]},
  {id:489,domain:T,question:"What is an injection attack?",options:["Malicious input sent to an interpreter","Physical hardware implants in systems","Injecting shellcode into process memory","Forging packets within a TCP session"],answer:0,explanation:"Injection attacks (SQL, command, LDAP, XPath, XML) exploit interpreters that incorrectly process untrusted data as executable code — prevented by parameterized queries and input validation.",optionExplanations:["Injection attacks exploit interpreters processing untrusted input as commands.","Hardware implants are a supply chain attack, not an interpreter-based injection.","Memory shellcode injection is a post-exploitation technique, distinct from input injection.","Packet forgery targets the network layer, not an application's input interpreter."]},
  {id:490,domain:G,question:"What is a security policy hierarchy?",options:["An incident escalation path","Controls ranked by effectiveness and cost","Policies, standards, procedures, and guidelines by specificity","Staff ranked by seniority"],answer:2,explanation:"Policies state what must be done; standards specify how; procedures give step-by-step instructions; guidelines offer best practice recommendations — each level provides increasing detail.",optionExplanations:["Escalation chains are incident response procedures, not a documentation hierarchy.","Control prioritization is risk management, not the policy hierarchy concept.","The hierarchy organizes documents from mandatory policies down to advisory guidelines.","Seniority ranking is an HR structure, not a documentation governance hierarchy."]},
  {id:491,domain:T,question:"What is domain generation algorithm (DGA) malware?",options:["C2 traffic routed through legitimate cloud services","Registering many domains for spam campaigns","Algorithmically generating many domains for C2","A legitimate DNS testing tool"],answer:2,explanation:"DGA malware (Conficker, GameOver Zeus) generates hundreds of daily domains — defenders must sink-hole all possible domains while attackers only need to register one that isn't blocked.",optionExplanations:["Routing through legitimate services is domain fronting, a different technique from DGA.","Bulk domain registration for spam uses static domains, unlike algorithmic generation.","DGA malware generates many pseudorandom domains so only one needs to be registered for contact.","Legitimate DNS testing tools serve operations, not resilient malware C2 infrastructure."]},
  {id:492,domain:A,question:"What is a bastion host?",options:["A reinforced physical data center facility","A standby failover server","Hardened single-entry server","A DMZ server hosting security tools"],answer:2,explanation:"Bastion hosts have minimal software, enhanced logging, strict access controls, and serve as the only authorized path into a secured network zone — like a jump server for administrative access.",optionExplanations:["A fortified facility is physical infrastructure, not a network-facing server.","Failover servers provide redundancy, not a controlled entry point.","A bastion host is stripped-down and hardened as the sole controlled path into a network.","A security tool server hosts applications, unlike a bastion's role as an entry point."]},
  {id:493,domain:O,question:"What is a cyber threat intelligence (CTI) program?",options:["Producing actionable intelligence on threat actors","Reporting cybercrime to law enforcement","Threat modeling during application design","A historical incident record repository"],answer:0,explanation:"CTI programs analyze strategic intelligence (who is targeting us, why), operational intelligence (current campaigns), and tactical intelligence (IoCs, TTPs) to improve defenses.",optionExplanations:["CTI analyzes threat data to produce intelligence supporting defensive decisions.","Law enforcement reporting is an incident response obligation, not intelligence production.","Threat modeling is an application design activity, not ongoing threat actor tracking.","Incident records are historical logs; CTI produces forward-looking analysis of threats."]},
  {id:494,domain:P,question:"What is a legitimate interest basis for processing personal data under GDPR?",options:["Basis allowing public authorities to process data","Balancing business interests against individual rights","Any documented business justification","Automatic lawfulness for commercial purposes"],answer:1,explanation:"Legitimate interest requires: purpose test (is the interest legitimate?), necessity test (is processing needed?), and balancing test (do legitimate interests override individual rights?).",optionExplanations:["Public task is a separate GDPR basis for government processing.","Legitimate interest requires a three-part test balancing interests against individual rights.","Not every business reason qualifies without passing the required balancing test.","Commercial purpose alone doesn't confer lawfulness without the legitimate interest assessment."]},
  {id:495,domain:G,question:"What is quantum cryptography and how does it differ from quantum-resistant cryptography?",options:["QKD for key exchange; post-quantum uses classical math","Post-quantum algorithms that require quantum computers to run","QKD is theoretical; post-quantum is standardized","Interchangeable terms for the same approach"],answer:0,explanation:"QKD (quantum key distribution) physically detects eavesdropping; post-quantum cryptography (CRYSTALS-Kyber, CRYSTALS-Dilithium) uses math problems quantum computers can't efficiently solve.",optionExplanations:["QKD uses quantum physics for key exchange, while post-quantum algorithms run on classical hardware.","Post-quantum algorithms run on classical computers, designed to resist quantum attacks.","QKD is commercially deployed by real vendors, not merely theoretical.","The two terms describe different approaches and are not interchangeable."]},
  {id:496,domain:T,question:"What is a ransomware-as-a-service (RaaS) model?",options:["Government surveillance of ransomware groups","An incident response firm's decryption service","Ransomware tools leased to affiliates","A sandbox platform for analyzing ransomware"],answer:2,explanation:"RaaS (LockBit, BlackCat/ALPHV) lowers the barrier to ransomware attacks — affiliates don't need to develop malware, only conduct attacks — explaining the explosion of ransomware groups.",optionExplanations:["Government disruption efforts are law enforcement activity, not the RaaS business model.","Recovery services help victims after an attack, not the criminal distribution model.","RaaS operators provide tools and infrastructure to affiliates who share ransom proceeds.","Legitimate analysis sandboxes help defenders, unlike the criminal RaaS model."]},
  {id:497,domain:A,question:"What is mutual authentication?",options:["Multiple users logging in simultaneously","Mutual identity verification","Sequential multi-step credential entry","Two admins approving a privileged action"],answer:1,explanation:"Mutual TLS (mTLS) has both client and server present certificates — API security commonly requires mTLS to ensure only authorized systems can call APIs, not just anyone with credentials.",optionExplanations:["Concurrent logins by different users is unrelated to mutual identity verification.","Mutual authentication, like mTLS, has both client and server present credentials.","Sequential credential steps describe MFA, not bidirectional identity verification.","Dual-admin approval is a separation-of-duties control, not mutual authentication."]},
  {id:498,domain:O,question:"What is the NIST Cybersecurity Framework (CSF) core structure?",options:["Prepare, Prevent, Detect, Contain, Eradicate","Govern, Identify, Protect, Detect, Respond, Recover (CSF 2.0)","Identify, Protect, Detect, Respond, Recover","Plan, Do, Check, Act"],answer:2,explanation:"NIST CSF 1.1's five functions provide a common language for cybersecurity risk management — CSF 2.0 adds Govern as a sixth function encompassing cybersecurity governance.",optionExplanations:["This resembles incident response phases, not the NIST CSF core structure.","This is the newer CSF 2.0 structure; the classic five-function version omits Govern.","NIST CSF organizes activities into these five core functions across the security lifecycle.","PDCA is the ISO 27001 management cycle, not the NIST CSF structure."]},
  {id:499,domain:T,question:"What is a trojanized software update?",options:["A mandatory forced update push","An update requesting excessive permissions","A poorly optimized update causing slowdowns","A legitimate update compromised to deliver malware"],answer:3,explanation:"SolarWinds, Asus Live Update, and NotPetya (disguised as M.E.Doc accounting software) are examples of trojanized updates that compromise thousands of targets simultaneously.",optionExplanations:["Forced update pushes are a deployment policy, not evidence of compromise.","Excessive permission requests may be suspicious but don't define a trojanized update.","Performance regressions are quality defects, not malicious compromise.","Attackers compromise the update distribution chain so trusted updates deliver malware."]},
  {id:500,domain:G,question:"What is the CIA triad?",options:["Government classification levels","Confidentiality, Integrity, and Availability","A CIA operational security model","CIA counterintelligence protocols"],answer:1,explanation:"Every security control maps to CIA: encryption preserves Confidentiality, checksums verify Integrity, redundancy ensures Availability — these three properties define information security.",optionExplanations:["Confidential, Secret, and Top Secret are government classification tiers, not the CIA triad.","The CIA triad defines the three core information security objectives.","Intelligence agency security models are unrelated to this information security concept.","Counterintelligence protocols belong to the agency, not the information security acronym."]},
  {id:501,domain:O,question:"What is application whitelisting?",options:["Blocking risky email attachments","Pre-approving SaaS applications for use","Allowing only approved software to run","A vetted list of approved vendors"],answer:2,explanation:"Application whitelisting (Windows AppLocker, WDAC) is one of the most effective controls against malware — if malware isn't on the allowed list, it cannot execute regardless of how it arrives.",optionExplanations:["This describes an email security gateway control, not endpoint whitelisting.","This is SaaS governance, not application whitelisting.","Application whitelisting permits only explicitly approved executables to run.","This is vendor procurement vetting, not a technical control."]},
  {id:502,domain:T,question:"What is a business email compromise (BEC) attack?",options:["Breaching an email server","Fraud using compromised business email","Bulk spam sent from a company domain","Malware attached to email"],answer:1,explanation:"BEC attacks (costing billions annually) impersonate executives (CEO fraud) or vendors, manipulating employees into wire transfers or payroll redirections.",optionExplanations:["Server compromise may enable BEC but isn't its definition.","BEC uses impersonated or hacked business email to authorize fraud.","This is domain abuse spam, not targeted fraud.","This describes phishing malware delivery, not BEC."]},
  {id:503,domain:A,question:"What is a demilitarized zone (DMZ) in the context of industrial control systems (ICS)?",options:["An unmonitored, unsecured network zone","A test lab for ICS engineers","An IT/OT network buffer zone","A buffer zone between hostile nations"],answer:2,explanation:"ICS DMZs prevent direct connectivity between business IT and critical OT networks — a jump server in the DMZ provides controlled, monitored access to OT systems.",optionExplanations:["DMZs enforce controls; they aren't security-free zones.","This describes a staging lab, not a DMZ.","The ICS DMZ monitors and controls data flow between IT and OT.","This is the military meaning of DMZ, unrelated to ICS."]},
  {id:504,domain:P,question:"What is cross-border data transfer regulation under GDPR?",options:["Undersea cable interconnection standards","Customs rules for hardware shipments","Postal rules for physical records","Restrictions on sending EU data abroad"],answer:3,explanation:"GDPR Chapter V restricts transfers to non-adequate countries — organizations use SCCs (Standard Contractual Clauses), BCRs, or adequacy decisions to enable lawful transfers.",optionExplanations:["This is telecom infrastructure regulation, not data protection.","This is trade law for equipment, not personal data.","This is postal and customs law, not data protection.","GDPR restricts transferring personal data outside the EU/EEA without safeguards."]},
];
